1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type Step = { op: "quote"; items: Item[] };
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
15	
16	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
17	
18	const COMPONENT_TYPES = new Set(["rune"]);
19	const BLOCK_SIZE = 3;
20	const BLOCK_BASE_PREMIUM = 60;
21	
22	const sumBasePremiums = (items: Item[]): number =>
23	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
24	
25	const componentSubtotalOf = (components: Item[]): number => {
26	  if (components.length === BLOCK_SIZE) {
27	    return BLOCK_BASE_PREMIUM;
28	  }
29	  return sumBasePremiums(components);
30	};
31	
32	const policyBaseOf = (items: Item[]): number => {
33	  const components = items.filter((it) => COMPONENT_TYPES.has(it.type));
34	  const mainItems = items.filter((it) => !COMPONENT_TYPES.has(it.type));
35	  return sumBasePremiums(mainItems) + componentSubtotalOf(components);
36	};
37	
38	const firstInsuranceSurchargeOf = (policyBase: number): number =>
39	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
40	
41	const quotePremium = (items: Item[]): number => {
42	  const policyBase = policyBaseOf(items);
43	  return policyBase + firstInsuranceSurchargeOf(policyBase) + PROCESSING_FEE;
44	};
45	
46	export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
47	  const results = scenario.steps.map((step) => ({ premium: Math.ceil(quotePremium(step.items)) }));
48	  return { results };
49	};
